hooks.command:
if echo "$CLAUDE_HOOK_FILE_PATH" | grep -qE 'migrations/.*\.exs$'; then INPUT=$(cat "$CLAUDE_HOOK_FILE_PATH" 2>/dev/null); ISSUES=''; if echo "$INPUT" | grep -qE 'references\(' && ! echo "$INPUT" | grep -qE 'create\s+(unique_)?index'; then ISSUES="${ISSUES}
   - Missing index on foreign key column(s). Add: create index(:table, [:foreign_key_id])"; fi; if echo "$INPUT" | grep -qE 'references\(' && ! echo "$INPUT" | grep -qE 'on_delete:'; then ISSUES="${ISSUES}
   - Missing on_delete strategy on references(). Specify on_delete: :delete_all, :nothing, or :nilify_all"; fi; if echo "$INPUT" | grep -qE 'add\s+:.*(:[a-z_]+_datetime|:utc_datetime)' && ! echo "$INPUT" | grep -qE 'timestamps\(\)'; then true; fi; if echo "$INPUT" | grep -qE 'remove\s+:' && ! echo "$INPUT" | grep -qE '#.*safety|#.*two-step|#.*deploy'; then ISSUES="${ISSUES}
   - Removing column without safety comment. Use a two-step migration: (1) stop reading column, deploy, (2) remove column"; fi; if echo "$INPUT" | grep -qE 'modify.*null:\s*false' && ! echo "$INPUT" | grep -qE 'default:'; then ISSUES="${ISSUES}
   - Adding NOT NULL without default. This locks the table on large datasets. Add a default value."; fi; if [ -n "$ISSUES" ]; then echo "⚠️  Migration Safety Check:$ISSUES" && exit 1; fi; fi; exit 0
